#title-block-header { display: none; }
.pub-container { display: grid; grid-template-columns: 80px 1fr 300px; gap: 30px; align-items: start; margin-top: 40px; }
.pub-index { font-size: 1.2em; font-weight: bold; color: #555; }
.pub-url { font-size: 0.8em; display: block; margin-top: 10px; text-decoration: none; color: #0366d6; }
.pub-citation { font-size: 1.1em; line-height: 1.6; }
.pub-toc img { width: 100%; height: auto; border: 1px solid #ddd; }
@media (max-width: 768px) { .pub-container { grid-template-columns: 1fr; gap: 20px; } }
